import React from 'react'
import { Avatar, Button, Input } from 'antd'
import { UserOutlined, EyeTwoTone, EyeInvisibleOutlined,ArrowRightOutlined } from '@ant-design/icons'
import './index.css'

export default function Register() {
  return (
    <div className='login'>
      <Avatar
        size={100}
      />
      <Input
        size='large'
        placeholder='input id'
        style={{
          width: '200px',
          marginBottom: "20px",
          marginTop: "30px"
        }}
        suffix={<UserOutlined />}
      ></Input>
      <Input.Password
        size='large'
        placeholder="input password"
        style={{
          width: '200px',
        }}
        prefix={(visible) => (visible ? <EyeTwoTone /> : <EyeInvisibleOutlined />)}
      />
      <Button ghost style={{ marginTop: '20px' }} >Register</Button>
      <Button
        style={{ marginTop: '170px' }}
        type='link'
        href='/login'
      >Login</Button>
    </div>
  )
}
